                </section>
              )}
            </div>
        ) : (
            <div className="flex items-center justify-center h-full flex-col gap-4 animate-in fade-in duration-1000">
               <div className="w-12 h-12 border-4 border-white/20 border-t-brand rounded-full animate-spin"></div>
               <span className="text-white/30 text-xs font-black uppercase tracking-widest">Preparando Visualização...</span>
            </div>
        )}
      </div>
    </div>
  );
};

export default ProposalBuilder;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { ProposalItem, StrategicMapItem, ProposalMetadata, SolutionItem, ProposalRecord, AppCustomization, ProposalSections } from '../types';
import { generateStrategicMapping, improveObservationText } from '../services/gemini';
import { SupabaseService } from '../services/api';
import ProposalPresentation from './ProposalPresentation';

interface ProposalBuilderProps {
  appConfig: AppCustomization;
}

const PhantPattern = () => (
  <svg width="100%" height="100%" className="absolute inset-0 pointer-events-none opacity-[0.03]">
    <pattern id="phant-text" x="0" y="0" width="200" height="100" patternUnits="userSpaceOnUse">
      <text x="10" y="60" fontFamily="Inter" fontWeight="900" fontSize="40" fill="currentColor">PHANT</text>
    </pattern>
    <rect width="100%" height="100%" fill="url(#phant-text)" />
  </svg>
);

const ProposalBuilder: React.FC<ProposalBuilderProps> = ({ appConfig }) => {
  // --- STATE MANAGEMENT ---
  const [proposalItems, setProposalItems] = useState<ProposalItem[]>([]);
  const [strategicMap, setStrategicMap] = useState<StrategicMapItem[]>([]);
  const [catalog, setCatalog] = useState<SolutionItem[]>([]);
  const [proposalHistory, setProposalHistory] = useState<ProposalRecord[]>([]);

  // Controle de Seções Ativas (SOLICITADO)
  const [selectedSections, setSelectedSections] = useState<ProposalSections>({
    cover: true,
    strategicMap: true,
    tacticalScope: true,
    finalInvestment: true,
    backCover: true
  });

  const [metadata, setMetadata] = useState<ProposalMetadata>({
    clientName: '',
    industry: '',
    website: '',
    instagram: '',
    meetingNotesPains: '',
    meetingNotesDesires: '',
    observations: '',
    date: new Date().toLocaleDateString('pt-BR'),
    consultant: 'Estrategista PhantLab',
    headline: 'PROPOSTA DE MOVIMENTO ESTRATÉGICO',
    discountType: 'fixed',
    discountValue: 0
  });

  // UI States
  const [isPreviewReady, setIsPreviewReady] = useState(false);
  const [activeTab, setActiveTab] = useState<'info' | 'solutions' | 'mapping' | 'history'>('info');
  const [zoom, setZoom] = useState(0.55); // Ajustado para tela cheia
  const [isFullscreen, setIsFullscreen] = useState(false);

  // Async Process States
  const [isGeneratingAI, setIsGeneratingAI] = useState(false);
  const [isImprovingText, setIsImprovingText] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [validationError, setValidationError] = useState<string | null>(null);

  const previewRef = useRef<HTMLDivElement>(null);

  // --- INITIALIZATION ---
  useEffect(() => {
    const saved = localStorage.getItem('phant_current_proposal');
    if (saved) setProposalItems(JSON.parse(saved));
    SupabaseService.fetchSolutions().then(data => setCatalog(data || []));
    loadHistory();

    const timer = setTimeout(() => setIsPreviewReady(true), 800);
    return () => clearTimeout(timer);
  }, []);

  const loadHistory = async () => {
    const history = await SupabaseService.fetchProposalsHistory();
    setProposalHistory(history || []);
  };

  const subTotal = useMemo(() => proposalItems.reduce((acc, curr) => acc + curr.totalPrice, 0), [proposalItems]);

  const discountAmount = useMemo(() => {
    if (!metadata.discountValue || metadata.discountValue <= 0) return 0;
    if (metadata.discountType === 'percentage') {
      return subTotal * (metadata.discountValue / 100);
    }
    return metadata.discountValue;
  }, [subTotal, metadata.discountValue, metadata.discountType]);

  const finalTotal = Math.max(0, subTotal - discountAmount);

  const formatCurrency = (val: number) => 
    new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  // --- HANDLERS ---
  const handleGenerateAI = async () => {
    if (!metadata.clientName) {
      showError("Defina o cliente para análise.");
      return;
    }
    setIsGeneratingAI(true);
    try {
      const mapping = await generateStrategicMapping(metadata);
      setStrategicMap(mapping || []);
      setActiveTab('mapping');
      setSelectedSections(prev => ({...prev, strategicMap: true}));
    } catch (err) {
      showError("IA indisponível.");
    } finally {
      setIsGeneratingAI(false);
    }
  };

  const handleAddSolution = (sol: SolutionItem) => {
    const newItem: ProposalItem = {
      instanceId: `manual-${Date.now()}`,
      solutionId: sol.id,
      name: sol.solucao,
      basePrice: sol.valor_base_num,
      selectedOptions: [],
      totalPrice: sol.valor_base_num,
      duration: sol.duracao,
      description: sol.descricao,
      deliverables: sol.entregaveis || []
    };
    setProposalItems(prev => [...prev, newItem]);
    setSelectedSections(prev => ({...prev, tacticalScope: true}));
  };

  const removeSolution = (id: string) => {
    setProposalItems(prev => prev.filter(p => p.instanceId !== id));
  };

  const showError = (msg: string) => {
    setValidationError(msg);
    setTimeout(() => setValidationError(null), 3000);
  };

  const saveToCloud = async () => {
    if (!metadata.clientName) {
      showError("Nome do cliente obrigatório.");
      setActiveTab('info');
      return;
    }
    setIsSaving(true);
    try {
      await SupabaseService.saveProposal(metadata.clientName, metadata.industry || "N/A", finalTotal, metadata.consultant, proposalItems, metadata);
      await loadHistory();
      alert("Proposta arquivada.");
    } finally {
      setIsSaving(false);
    }
  };

  const handleOpenProposal = () => {
    const sourceElement = document.getElementById('proposal-pages-container');
    if (!sourceElement) return;

    const newWindow = window.open('', '_blank');
    if (!newWindow) return;

    const htmlContent = `
        <!DOCTYPE html>
        <html lang="pt-BR">
        <head>
            <meta charset="UTF-8">
            <title>PROPOSTA - ${metadata.clientName}</title>
            <script src="https://cdn.tailwindcss.com"></script>
            <link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700;800;900&display=swap" rel="stylesheet">
            <style>
                body { font-family: 'Inter', sans-serif; background-color: #1a1a1a; margin: 0; padding: 40px; display: flex; justify-content: center; min-height: 100vh; }
                #proposal-root { display: flex; flex-direction: column; gap: 40px; transform: scale(1) !important; }
                .printable-page { width: 210mm; height: 297mm; background: white; position: relative; overflow: hidden; box-shadow: 0 0 50px rgba(0,0,0,0.5); }
                @media print { body { background: none; padding: 0; } #proposal-root { gap: 0; } .printable-page { box-shadow: none; margin: 0; page-break-after: always; } }
            </style>
        </head>
        <body><div id="proposal-root">${sourceElement.innerHTML}</div></body>
        </html>
    `;
    newWindow.document.write(htmlContent);
    newWindow.document.close();
  };

  const handleOpenPresentation = () => {
    const sourceElement = document.getElementById('presentation-hidden-source');
    if (!sourceElement) return;

    const newWindow = window.open('', '_blank');
    if (!newWindow) return;

    const htmlContent = `
        <!DOCTYPE html>
        <html lang="pt-BR">
        <head>
            <meta charset="UTF-8">
            <meta name="viewport" content="width=device-width, initial-scale=1.0">
            <title>APRESENTAÇÃO - ${metadata.clientName}</title>
            <script src="https://cdn.tailwindcss.com"></script>
            <link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700;800;900&display=swap" rel="stylesheet">
            <style>
              body { margin: 0; padding: 0; font-family: 'Inter', sans-serif; background: black; color: white; overflow-x: hidden; }
              * { box-sizing: border-box; }
            </style>
        </head>
        <body><div id="presentation-root">${sourceElement.innerHTML}</div></body>
        </html>
    `;
    newWindow.document.write(htmlContent);
    newWindow.document.close();
  };

  const SectionToggle = ({ label, checked, onChange }: { label: string, checked: boolean, onChange: (val: boolean) => void }) => (
    <button 
      onClick={() => onChange(!checked)}
      className={`flex items-center justify-between p-3 rounded-xl border transition-all ${checked ? 'bg-black text-white border-black shadow-md' : 'bg-gray-50 text-gray-400 border-transparent'}`}
    >
      <span className="text-[9px] font-black uppercase tracking-widest">{label}</span>
      <div className={`w-2.5 h-2.5 rounded-full ${checked ? 'bg-emerald-400' : 'bg-gray-300'}`}></div>
    </button>
  );

  return (
    <div className={`flex flex-col lg:flex-row gap-8 animate-in fade-in duration-700 ${isFullscreen ? 'fixed inset-0 z-[100] bg-[#1a1a1a] p-0' : ''}`}>

      {/* RENDERIZADOR OCULTO PARA APRESENTAÇÃO EM NOVA ABA */}
      <div id="presentation-hidden-source" className="hidden">
        <ProposalPresentation 
          metadata={metadata} 
          items={proposalItems} 
          strategicMap={strategicMap} 
          appConfig={appConfig}
          selectedSections={selectedSections}
        />
      </div>

      {/* PAINEL DE CONTROLE */}
      {!isFullscreen && (
        <div className="w-full lg:w-[420px] space-y-8 no-print shrink-0">
          <header className="space-y-1">
            <h2 className="text-4xl font-black text-gray-900 tracking-tighter">Gerar Propostas.</h2>
            <p className="text-gray-400 text-sm font-medium">Configure as seções e dados do cliente.</p>
          </header>

          <div className="bg-white rounded-[40px] border border-gray-100 shadow-xl overflow-hidden flex flex-col h-[780px] relative">
            <nav className="flex p-3 gap-1 bg-gray-50 border-b border-gray-100 no-print">
              {(['info', 'solutions', 'mapping', 'history'] as const).map(t => (
                <button 
                  key={t}
                  onClick={() => setActiveTab(t)}
                  className={`flex-1 py-3 rounded-2xl text-[9px] font-black uppercase tracking-widest transition-all ${activeTab === t ? 'bg-black text-white' : 'text-gray-400'}`}
                >
                  {t === 'info' ? 'Seções' : t === 'solutions' ? 'Itens' : t === 'mapping' ? 'Estratégia' : 'Histórico'}
                </button>
              ))}
            </nav>

            <div className="flex-1 overflow-y-auto p-6 space-y-6 custom-scrollbar no-print">
              {activeTab === 'info' && (
                <div className="space-y-6 animate-in slide-in-from-left-4">
                  {/* SELETOR DE SEÇÕES (SOLICITADO) */}
                  <div className="space-y-3">
                     <p className="text-[9px] font-black uppercase tracking-widest text-gray-300 ml-1">Configuração do Documento</p>
                     <div className="grid grid-cols-2 gap-2">
                        <SectionToggle label="1. Capa" checked={selectedSections.cover} onChange={v => setSelectedSections(p => ({...p, cover: v}))} />
                        <SectionToggle label="2. Mapa" checked={selectedSections.strategicMap} onChange={v => setSelectedSections(p => ({...p, strategicMap: v}))} />
                        <SectionToggle label="3. Escopo" checked={selectedSections.tacticalScope} onChange={v => setSelectedSections(p => ({...p, tacticalScope: v}))} />
                        <SectionToggle label="4. Resumo" checked={selectedSections.finalInvestment} onChange={v => setSelectedSections(p => ({...p, finalInvestment: v}))} />
                        <SectionToggle label="5. Final" checked={selectedSections.backCover} onChange={v => setSelectedSections(p => ({...p, backCover: v}))} />
                     </div>
                  </div>

                  <div className="space-y-4 pt-4 border-t border-gray-100">
                    <label className="text-[10px] font-black uppercase tracking-widest text-gray-300 ml-1">Dados Básicos</label>
                    <input 
                      value={metadata.clientName}
                      onChange={e => setMetadata({...metadata, clientName: e.target.value.toUpperCase()})}
                      className="w-full bg-gray-50 p-4 rounded-2xl font-black text-sm outline-none border focus:border-brand"
                      placeholder="NOME DO CLIENTE"
                    />
                    <div className="grid grid-cols-2 gap-3">
                        <input value={metadata.website} onChange={e => setMetadata({...metadata, website: e.target.value})} className="w-full bg-gray-50 p-4 rounded-xl font-bold text-[11px] outline-none" placeholder="website.com.br" />
                        <input value={metadata.instagram} onChange={e => setMetadata({...metadata, instagram: e.target.value})} className="w-full bg-gray-50 p-4 rounded-xl font-bold text-[11px] outline-none" placeholder="@perfil" />
                    </div>
                  </div>

                  <button 
                    onClick={handleGenerateAI}
                    disabled={isGeneratingAI}
                    className="w-full py-5 bg-black text-white rounded-[28px] font-black text-[10px] uppercase tracking-widest hover:scale-105 transition-all shadow-lg"
                  >
                    {isGeneratingAI ? 'MAPEANDO...' : '✨ Mapear com IA'}
                  </button>
                </div>
              )}

              {activeTab === 'solutions' && (
                <div className="space-y-6 animate-in slide-in-from-left-4">
                   <h4 className="text-[10px] font-black text-gray-300 uppercase tracking-widest ml-1">Carrinho de Soluções</h4>
                   {proposalItems.map(item => (
                      <div key={item.instanceId} className="p-4 bg-gray-50 rounded-2xl flex justify-between items-center group border border-transparent hover:border-gray-200 transition-all">
                        <div>
                          <p className="font-black text-[11px] truncate w-48">{item.name}</p>
                          <p className="text-[9px] text-brand font-bold uppercase">{formatCurrency(item.totalPrice)}</p>
                        </div>
                        <button onClick={() => removeSolution(item.instanceId)} className="text-gray-300 hover:text-red-500 p-2">
                          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M6 18L18 6M6 6l12 12"/></svg>
                        </button>
                      </div>
                   ))}

                   <div className="pt-4 border-t border-gray-100 space-y-3">
                      <h4 className="text-[10px] font-black text-gray-300 uppercase tracking-widest ml-1">Catálogo Rápido</h4>
                      <div className="space-y-2">
                        {catalog.map(sol => (
                          <button key={sol.id} onClick={() => handleAddSolution(sol)} className="w-full text-left p-3.5 bg-white border border-gray-100 rounded-xl hover:border-brand transition-all flex justify-between items-center group">
                            <span className="font-bold text-[11px] text-gray-600 group-hover:text-black">{sol.solucao}</span>
                            <span className="text-[8px] font-black text-brand">+ ADD</span>
                          </button>
                        ))}
                      </div>
                   </div>
                </div>
              )}

              {activeTab === 'mapping' && (
                <div className="space-y-4 animate-in slide-in-from-left-4">
                   {strategicMap.map((m, i) => (
                    <div key={i} className="p-5 bg-gray-50 rounded-[24px] border border-gray-100 space-y-3">
                        <textarea value={m.current} onChange={e => { const n = [...strategicMap]; n[i].current = e.target.value; setStrategicMap(n); }} className="w-full bg-transparent border-none p-0 text-[10px] font-medium text-gray-400 resize-none focus:ring-0" placeholder="Estado Atual" />
                        <div className="h-px bg-gray-200"></div>
                        <textarea value={m.desired} onChange={e => { const n = [...strategicMap]; n[i].desired = e.target.value; setStrategicMap(n); }} className="w-full bg-transparent border-none p-0 text-xs font-black text-gray-900 resize-none focus:ring-0" placeholder="Estado Desejado" />
                    </div>
                  ))}
                </div>
              )}
            </div>

            <div className="p-6 bg-black text-white space-y-4 no-print">
              <div className="grid grid-cols-2 gap-2">
                  <div className="flex flex-col">
                      <span className="text-[9px] font-black text-white/30 uppercase tracking-widest">Investimento Final</span>
                      <span className="text-3xl font-black tracking-tighter">{formatCurrency(finalTotal)}</span>
                  </div>
                  <div className="flex flex-col justify-end items-end gap-1">
                      <button onClick={saveToCloud} className="text-[8px] font-black text-white/40 border border-white/20 px-3 py-1 rounded-full uppercase hover:bg-white/10">Salvar Cópia</button>
                  </div>
              </div>

              <div className="grid grid-cols-2 gap-2">
                <button onClick={handleOpenProposal} className="w-full py-4 bg-emerald-600 text-white rounded-2xl font-black text-[9px] uppercase tracking-widest hover:bg-emerald-500 shadow-lg">ABRIR PDF</button>
                <button onClick={handleOpenPresentation} className="w-full py-4 bg-[#6113cc] text-white rounded-2xl font-black text-[9px] uppercase tracking-widest hover:scale-105 transition-all shadow-lg shadow-purple-500/20">APRESENTAÇÃO</button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* ÁREA DE PREVIEW (VISUALIZADOR AJUSTADO) */}
